const orders = $input.all();
const today = new Date().toLocaleDateString('en-BD', {timeZone:'Asia/Dhaka', day:'2-digit', month:'short', year:'numeric'});

let totalRevenue = 0;
let totalOrders = orders.length;
let completedOrders = 0;
let processingOrders = 0;
const productCount = {};

for (const item of orders) {
  const order = item.json;
  totalRevenue += parseFloat(order.total || 0);
  if (order.status === 'completed') completedOrders++;
  if (order.status === 'processing') processingOrders++;
  for (const line of (order.line_items || [])) {
    productCount[line.name] = (productCount[line.name] || 0) + line.quantity;
  }
}

const topProducts = Object.entries(productCount)
  .sort((a,b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, qty]) => `  • ${name}: ${qty} pcs`)
  .join('\n');

return [{
  json: {
    today,
    totalOrders,
    completedOrders,
    processingOrders,
    totalRevenue: totalRevenue.toFixed(2),
    topProducts: topProducts || '  No sales today'
  }
}];

